function Plus({size=14,className=""}:{size?:number;className?:string}){return(<svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} className={className}><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>);}

// ─── TYPES & API ──────────────────────────────────────────────────────────────
type AiQuota={tokens_balance:number;daily_free_used:number;daily_free_limit:number;free_remaining:number;total_ai_calls:number;packs:Array<{id:number;name:string;tokens:number;price_kes:number;desc:string}>;};
type DispatchStep={step:number;action:string;timing:string;kpi:string};
type RiskFactor={risk:string;severity:"HIGH"|"MED"|"LOW";mitigation:string};
type FaidaResult={route_score:number;recommendation:"EXECUTE"|"REVIEW"|"WAIT";confidence_pct:number;summary:string;execution_steps:DispatchStep[];risk_factors:RiskFactor[];optimal_volume_kg:number;projected_margin_pct:number;price_trend:"RISING"|"STABLE"|"FALLING";calculator_config:{kg:number;loss_pct:number;pkg_rate:number;notes:string};market_intel:string;quota:AiQuota;buy_price:number;sell_price:number;tc_kg:number;dist_km:number;error?:string};
type NegEvent={time:string;type:string;text:string;highlight?:boolean};
type Mshauri={fair_price:number;counter_price:number;market_avg:number;discount_pct:number;market_position:"ABOVE_MARKET"|"AT_MARKET"|"BELOW_MARKET";confidence:number;reasoning:string;negotiation_advice:string;events:NegEvent[];quota:AiQuota;bid_id:number;bid_price:number;error?:string};
const BASE=process.env.NEXT_PUBLIC_API_URL||"https://api.agritrade.gidraf.dev/api";
function withAuth(o:RequestInit={}):RequestInit{const t=typeof window!=="undefined"?localStorage.getItem("agritrade_token"):"";return{...o,headers:{"Content-Type":"application/json",...(t?{Authorization:`Bearer ${t}`}:{}),...((o.headers as any)||{})}};}
const aiApi={
  getQuota:():Promise<AiQuota>=>fetch(`${BASE}/ai/quota`,withAuth()).then(r=>r.json()),
  purchase:(pack_id:number,phone?:string)=>fetch(`${BASE}/ai/purchase`,withAuth({method:"POST",body:JSON.stringify({pack_id,phone})})).then(r=>r.json()),
  dispatch:(p:{commodity_id:string;origin_market_id:number;target_market_id:number}):Promise<FaidaResult>=>fetch(`${BASE}/ai/faida/dispatch`,withAuth({method:"POST",body:JSON.stringify(p)})).then(r=>r.json()),
  MshauriAnalyze:(bid_id:number):Promise<Mshauri>=>fetch(`${BASE}/ai/Mshauri/analyze`,withAuth({method:"POST",body:JSON.stringify({bid_id})})).then(r=>r.json()),
  MshauriAction:(bid_id:number,action:string,price?:number)=>fetch(`${BASE}/ai/Mshauri/action`,withAuth({method:"POST",body:JSON.stringify({bid_id,action,price})})).then(r=>r.json()),
};

